// Virtual Circuit Switching - Packet Forwarding
PROCEDURE ForwardPacket(packet, incomingInterface)
BEGIN
    // Get VCI from packet header
    vci ← packet.virtualCircuitIdentifier

    // Look up VCI in routing table
    entry ← VCI_Table[incomingInterface][vci]

    IF entry EXISTS THEN
        // Replace VCI with outgoing VCI (label swapping)
        packet.virtualCircuitIdentifier ← entry.outgoingVCI

        // Forward packet on outgoing interface
        SendToInterface(packet, entry.outgoingInterface)
    ELSE
        // VCI not found - drop packet
        DropPacket(packet)
    END IF
END

// Datagram Switching - Independent Packet Routing
PROCEDURE ForwardDatagram(packet)
BEGIN
    // Extract destination address from packet
    destAddress ← packet.destinationIP

    // Perform longest prefix match routing lookup
    nextHop ← RoutingTable.Lookup(destAddress)

    IF nextHop EXISTS THEN
        // No connection ID - address stays the same
        // Forward packet to next hop router
        SendToNextHop(packet, nextHop)
    ELSE
        // No route to destination
        SendICMPError(source, "Network Unreachable")
    END IF
END

// Example: Each packet makes independent decision
PROCEDURE ProcessMultiplePackets(packets[])
BEGIN
    FOR EACH packet IN packets DO
        // Each packet routed independently
        ForwardDatagram(packet)
    END FOR
END

#include <stdio.h>
#include <stdbool.h>

typedef struct {
    unsigned int src_ip;
    unsigned int dest_ip;
    unsigned short src_port;
    unsigned short dest_port;
    unsigned char payload[1000];
    unsigned int sequence;
} DatagramPacket;

typedef struct {
    unsigned int dest_network;
    unsigned int subnet_mask;
    unsigned int next_hop;
    char interface[10];
} RoutingEntry;

// Simple routing table lookup (longest prefix match)
unsigned int find_next_hop(DatagramPacket *packet, RoutingEntry *table, int table_size) {
    unsigned int dest = packet->dest_ip;
    unsigned int best_match = 0;
    unsigned int next_hop = 0;

    for (int i = 0; i < table_size; i++) {
        unsigned int network = table[i].dest_network & table[i].subnet_mask;
        unsigned int dest_masked = dest & table[i].subnet_mask;

        if (network == dest_masked) {
            // Check for longest prefix match
            if (table[i].subnet_mask >= best_match) {
                best_match = table[i].subnet_mask;
                next_hop = table[i].next_hop;
            }
        }
    }
    return next_hop;
}

// Process each datagram independently
void process_datagram(DatagramPacket *packet, RoutingEntry *routing_table, int rt_size) {
    // Each packet requires full routing lookup
    printf("Processing Packet #%u\n", packet->sequence);
    printf("  Source IP: %u.%u.%u.%u\n", 
           (packet->src_ip >> 24) & 0xFF,
           (packet->src_ip >> 16) & 0xFF,
           (packet->src_ip >> 8) & 0xFF,
           packet->src_ip & 0xFF);
    printf("  Dest IP:   %u.%u.%u.%u\n",
           (packet->dest_ip >> 24) & 0xFF,
           (packet->dest_ip >> 16) & 0xFF,
           (packet->dest_ip >> 8) & 0xFF,
           packet->dest_ip & 0xFF);

    unsigned int next_hop = find_next_hop(packet, routing_table, rt_size);
    printf("  Next Hop:  %u.%u.%u.%u\n\n",
           (next_hop >> 24) & 0xFF,
           (next_hop >> 16) & 0xFF,
           (next_hop >> 8) & 0xFF,
           next_hop & 0xFF);
}

int main() {
    // Example: Each packet is routed independently
    DatagramPacket packets[3] = {
        {0xC0A80101, 0xC0A80105, 1000, 80, "", 1},
        {0xC0A80102, 0xC0A80106, 1001, 80, "", 2},
        {0xC0A80103, 0xC0A80107, 1002, 80, "", 3}
    };

    // Process each packet independently (no connection state)
    for (int i = 0; i < 3; i++) {
        process_datagram(&packets[i], NULL, 0);  // Routing table not shown
    }

    return 0;
}
